    // MARK: - Helper Methods for Creating Test Projects
    
    private func createTempDirectory() throws -> String {
        let tempDir = NSTemporaryDirectory() + "ArchitectureTest_" + UUID().uuidString
        try FileManager.default.createDirectory(atPath: tempDir, withIntermediateDirectories: true)
        return tempDir
    }
    
    private func cleanupTempDirectory(_ path: String) {
        try? FileManager.default.removeItem(atPath: path)
    }
    
    private func createSimpleTestProject() throws -> String {
        let projectDir = try createTempDirectory()
        
        // Create simple SwiftUI files
        let contentView = """
        import SwiftUI
        
        struct ContentView: View {
            @State private var isLoading: Bool = false
            
            var body: some View {
                VStack {
                    DetailView()
                    if isLoading {
                        ProgressView()
                    }
                }
            }
        }
        """
        
        let detailView = """
        import SwiftUI
        
        struct DetailView: View {
            @State private var title: String = ""
            
            var body: some View {
                Text(title)
            }
        }
        """
        
        try contentView.write(toFile: (projectDir as NSString).appendingPathComponent("ContentView.swift"), atomically: true, encoding: .utf8)
        try detailView.write(toFile: (projectDir as NSString).appendingPathComponent("DetailView.swift"), atomically: true, encoding: .utf8)
        
        return projectDir
    }
    
    private func createDuplicateStateProject() throws -> String {
        let projectDir = try createTempDirectory()
        
        let parentView = """
        import SwiftUI
        
        struct ParentView: View {
            @State private var isLoading: Bool = false
            @State private var userName: String = ""
            
            var body: some View {
                VStack {
                    ChildView()
                    if isLoading {
                        ProgressView()
                    }
                }
            }
        }
        """
        
        let childView = """
        import SwiftUI
        
        struct ChildView: View {
            @State private var isLoading: Bool = false  // Duplicate
            @State private var userName: String = ""   // Duplicate
            
            var body: some View {
                Text("Child: \\(userName)")
            }
        }
        """
        
        try parentView.write(toFile: (projectDir as NSString).appendingPathComponent("ParentView.swift"), atomically: true, encoding: .utf8)
        try childView.write(toFile: (projectDir as NSString).appendingPathComponent("ChildView.swift"), atomically: true, encoding: .utf8)
        
        return projectDir
    }
    
    private func createComprehensiveTestProject() throws -> String {
        let projectDir = try createTempDirectory()
        
        // Create multiple views with various patterns
        let files = [
            ("RootView.swift", """
            import SwiftUI
            
            struct RootView: View {
                @State private var globalData: String = ""
                @StateObject private var viewModel = ViewModel()
                
                var body: some View {
                    NavigationView {
                        VStack {
                            ContentView()
                            SettingsView()
                        }
                    }
                }
            }
            """),
            ("ContentView.swift", """
            import SwiftUI
            
            struct ContentView: View {
                @State private var globalData: String = ""  // Duplicate
                @State private var isVisible: Bool = true
                
                var body: some View {
                    VStack {
                        DetailView()
                        if isVisible {
                            Text("Visible")
                        }
                    }
                    .sheet(isPresented: .constant(true)) {
                        SheetView()
                    }
                }
            }
            """),
            ("DetailView.swift", """
            import SwiftUI
            
            struct DetailView: View {
                @State private var isVisible: Bool = true   // Duplicate
                @ObservedObject var model: DataModel
                
                var body: some View {
                    Text("Detail")
                        .fullScreenCover(isPresented: .constant(false)) {
                            ModalView()
                        }
                }
            }
            """),
            ("SettingsView.swift", """
            import SwiftUI
            
            struct SettingsView: View {
                @State private var globalData: String = ""  // Another duplicate
                @EnvironmentObject var appState: AppState
                
                var body: some View {
                    Text("Settings")
                }
            }
            """),
            ("SheetView.swift", """
            import SwiftUI
            
            struct SheetView: View {
                @State private var localData: String = ""
                
                var body: some View {
                    Text("Sheet")
                }
            }
            """),
            ("ModalView.swift", """
            import SwiftUI
            
            struct ModalView: View {
                @State private var modalData: Bool = false
                
                var body: some View {
                    Text("Modal")
                }
            }
            """)
        ]
        
        for (fileName, content) in files {
            try content.write(toFile: (projectDir as NSString).appendingPathComponent(fileName), atomically: true, encoding: .utf8)
        }
        
        return projectDir
    }
    
    private func createLargeTestProject() throws -> String {
        let projectDir = try createTempDirectory()
        
        // Create many files to test performance
        for index in 0..<50 {
            let viewContent = """
            import SwiftUI
            
            struct TestView\(index): View {
                @State private var data\(index): String = ""
                @State private var isLoading: Bool = false
                
                var body: some View {
                    VStack {
                        Text("View \(index)")
                        if isLoading {
                            ProgressView()
                        }
                    }
                }
            }
            """
            
            try viewContent.write(toFile: (projectDir as NSString).appendingPathComponent("TestView\(index).swift"), atomically: true, encoding: .utf8)
        }
        
        return projectDir
    }
}
